  /**
   * 请求数据
   */
  postData() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url =
      this.listUrl.indexOf("http://") !== -1 || this.listUrl.indexOf("https://") !== -1
        ? "http://192.168.0.82:8080/dsfa/teas/jwgl/bjgl/listClassForPersonNetSign"
        : dsf.url.getWebPath(this.listUrl);
    dsf.http
      .request(url, _this.parms, "get")
      .done(response => {
        if (response.state === 20000) {
          // 请求成功
          this.postDataSuccess(response.data);
        }
      })
      .error(response => {
        // 请求错误
        dsf.layer.message("请求异常", false);
      })
      .always(response => {
        dsf.layer.close(loading);
      })
      .exec();
  }

