  courseSingUp(id, state, userName, userId) {
    //报名成功后刷新列表
    let params = {
      classId: id,
      // nc_students_id: userId,
    };
    let that = this;
    let loading = dsf.layer.loadding();
    let singUrl = "";
    if (state == 1) {
      singUrl =
        this.signUpUrl.indexOf("http://") !== -1 || this.signUpUrl.indexOf("https://") !== -1 ? this.signUpUrl : dsf.url.getWebPath(this.signUpUrl);
    } else if (state == 3) {
      singUrl = this.backUrl.indexOf("http://") !== -1 || this.backUrl.indexOf("https://") !== -1 ? this.backUrl : dsf.url.getWebPath(this.backUrl);
    }
    // singUrl = state == 1 ? dsf.url.getWebPath("teas/jwgl/bjgl/signUp") : dsf.url.getWebPath("teas/jwgl/bjgl/rejectSignUp");
    dsf.http
      .request(singUrl, params, "GET")
      .done(function(res) {
        if (res.success) {
          if (res.data) {
            dsf.layer.message(state == 1 ? "报名成功" : "退回成功", true);
            let t = setTimeout(() => {
              if (that._root._isDesign) {
                that._postData();
              } else {
                that.postData();
              }
              clearTimeout(t);
            }, 1000);
          }
        } else {
          dsf.layer.message(res.message, false);
        }
      })
      .error(function(err) {
        console.log(err);
        dsf.layer.message(err.message, false);
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }
